const currentDomain = window.location.origin;

async function dl(fileUrl, filename) {
	try {
		const response = await fetch(fileUrl);
		if (!response.ok)
			throw new Error(`HTTP 错误: ${response.status}`);
		const blob = await response.blob();
		const url = URL.createObjectURL(blob);
		const link = document.createElement('a');
		link.href = url;
		link.download = filename;
		document.body.appendChild(link);
		link.click();
		document.body.removeChild(link);
		setTimeout(() => URL.revokeObjectURL(url), 100);

	} catch (error) {
		console.error('下载错误:', error);
	}
}

async function getip() {
	try {
		const response = await fetch("/cdn-cgi/trace"); // Request Cloudflare trace endpoint[span_2](start_span)[span_2](end_span)
		if (response.ok) {
			const data = await response.text();
			const lines = data.split("\n");
			const info = {};
			lines.forEach((line) => {
				const parts = line.split("=");
				if (parts.length === 2) {
					info[parts[0]] = parts[1];
				}
			});
			const displayText = `${info.loc} ${info.ip} | ${info.colo} | ${info.http} | ${info.tls} | ${info.kex}`;
			return displayText; // Return string directly instead of using undeclared variable[span_3](start_span)[span_3](end_span)
		}
	} catch (error) {
		console.error("获取失败: ", error);
	}
}

function gh(path) {
	const baseUrl = "https://gh.clun.top/raw.githubusercontent.com/FongMi/Release/refs/heads/";
	if (path) {
		window.open(baseUrl + path, '_blank');
	}
}

$(document).ready(async function() {
	// Fetch and display IP info immediately on load[span_4](start_span)[span_4](end_span)
	const ipData = await getip();
	if (ipData) {
		$("#cfs").text(ipData);
	} else {
		$("#cfs").text("Error loading IP info");
	}

	// Calculate and display page load time using camelCase variable[span_5](start_span)[span_5](end_span)
	var timeLoad = performance.now();
	$("#time").text("页面加载耗时 " + Math.round(timeLoad) + " 毫秒");
});